import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as l,e as o}from"./app-84f3504c.js";const c={},t=o('<h1 id="js-中-this" tabindex="-1"><a class="header-anchor" href="#js-中-this" aria-hidden="true">#</a> JS 中 this</h1><ol><li><p>作为普通函数执行时，<code>this</code>指向<code>window</code>。</p></li><li><p>当函数作为对象的方法被调用时，<code>this</code>就会指向<code>该对象</code>。</p></li><li><p>构造器调用，<code>this</code>指向<code>返回的这个对象</code>。</p></li><li><p><mark>箭头函数</mark> 箭头函数的<code>this</code>绑定看的是this所在函数定义在哪个对象下，就绑定哪个对象。如果有嵌套的情况，则this绑定到最近的一层对象上。</p></li><li><p>基于Function.prototype上的 <code>apply 、 call 和 bind </code>调用模式。<br><code>apply 、 call 和 bind </code>区别：</p><ul><li><p>三者都可以改变函数的this对象指向</p></li><li><p>三者第一个参数都是this要指向的对象，如果没有参数或参数=undefined或null，则默认指向window</p></li><li><p>apply传参为数组、call为参数列表，且它们是一次性传入参数。bind可以分为多次传入</p></li><li><p>apply、call是立即执行；bind是返回绑定this之后的函数，便于稍后调用。</p></li><li><p>bind会返回一个新的函数，如果这个新函数作为构造函数创建一个新的对象。那么this指向用new创建的实例。</p></li></ul></li></ol>',2),d=[t];function p(s,a){return e(),l("div",null,d)}const r=i(c,[["render",p],["__file","3.JS中的this.html.vue"]]);export{r as default};
